        // Because we only increase $nums[i]$, and the requirement is $nums[i] > nums[i \pm 1]$, the required value for $nums[i]$ is determined by $nums[i \pm 1]$.
        // If we process peaks in increasing index order, $nums[i-1]$ and $nums[i+1]$ are already at their final state *if they are not peaks themselves*.

        // Let's use the fixed configuration derived from K_max. The valleys are untouched.
        // For a peak $i$, the cost is $\max(0, \max(nums[i-1], nums[i+1]) + 1 - nums[i])$.

        // We must calculate the cost assuming the neighbors are *not* modified by *other* peaks, which is true in the dense packing where neighbors are valleys.

        let currentCost = 0;
        for (const i of peakIndices) {
            let requiredValue = 0;

            // Check left neighbor
            if (i > 0) {
                requiredValue = Math.max(requiredValue, nums[i - 1] + 1);
            }
            // Check right neighbor
            if (i < n - 1) {
                requiredValue = Math.max(requiredValue, nums[i + 1] + 1);
            }

            // Calculate cost to reach requiredValue
            const costForThisPeak = Math.max(0, requiredValue - nums[i]);
            currentCost += costForThisPeak;
        }

        return currentCost;
    };

    // --- Candidate A: Odd indices (1, 3, 5, ...) ---
    let peaksA = [];
    for (let i = 1; i <= n - 2; i += 2) {
        peaksA.push(i);
    }
    // Check if this configuration achieves K_max. It usually does unless n is very small.
    if (peaksA.length === K_max) {
        minCost = Math.min(minCost, calculateCost(peaksA));
    } else if (peaksA.length > K_max) {
        // This should not happen based on K_max derivation, but if it does, we might need to prune.
    }


    // --- Candidate B: Even indices (2, 4, 6, ...) ---
    let peaksB = [];
    for (let i = 2; i <= n - 2; i += 2) {
        peaksB.push(i);
    }
    // Check if this configuration achieves K_max.
    if (peaksB.length === K_max) {
        minCost = Math.min(minCost, calculateCost(peaksB));
    } else if (peaksB.length > K_max) {
        // Should not happen
    }

    // Edge case: If K_max cannot be achieved by these simple patterns, we might need a more complex dynamic programming approach.
    // However, given the constraints and the nature of the problem, the densest packing (alternating indices) should yield K_max.

    // If K_max was 0 (i.e., n < 3, handled already), minCost remains Infinity.
    if (minCost === Infinity) {
        return 0; // Should only happen if n < 3
    }

    return minCost;
