object Solution {
  /**
   * @param nums The input array.
   * @return The minimum total operations required.
   */
  def solve(nums: Array[Long]): Long = {
    val n = nums.length
    if (n < 3) {
      return 0L
    }

    // Maximum number of peaks K_max = ceil((n - 2) / 2)
    // In integer arithmetic: (n - 2 + 1) / 2 = (n - 1) / 2 using integer division, but we need ceil.
    // ceil(a/b) = (a + b - 1) / b
    // ceil((n-2)/2) = (n - 2 + 2 - 1) / 2 = (n - 1) / 2 if we use standard integer division for positive numbers, 
    // but let's use a safer ceiling calculation for clarity.
    val kMax = if (n <= 2) 0 else (n - 2 + 1) / 2

    /**
     * Calculates the cost to achieve peaks at the given indices, assuming neighbors are fixed at original values.
     * In the dense packing configurations (1, 3, 5, ...) or (2, 4, 6, ...), neighbors of peaks are valleys,
     * and since we only increase peaks, the neighbors' values remain fixed by the initial array values.
     * @param peakIndices The indices where we aim to create a peak.
     * @param initialNums The original array.
     * @return The total cost.
     */
    def calculateCost(peakIndices: Seq[Int], initialNums: Array[Long]): Long = {
      var currentCost: Long = 0L
      for (i <- peakIndices) {
        var requiredValue: Long = 0L

        // Check left neighbor (i-1)
        if (i > 0) {
          requiredValue = Math.max(requiredValue, initialNums(i - 1) + 1)
        }
        // Check right neighbor (i+1)
        if (i < n - 1) {
          requiredValue = Math.max(requiredValue, initialNums(i + 1) + 1)
        }

        // Calculate cost to reach requiredValue
        val costForThisPeak = Math.max(0L, requiredValue - initialNums(i))
        currentCost += costForThisPeak
      }
      currentCost
    }

    var minCost: Long = Long.MaxValue

    // --- Candidate A: Odd indices (1, 3, 5, ...) ---
    val peaksA = (1 to n - 2 step 2).toSeq
    if (peaksA.size == kMax) {
      minCost = Math.min(minCost, calculateCost(peaksA, nums))
    }

    // --- Candidate B: Even indices (2, 4, 6, ...) ---
    val peaksB = (2 to n - 2 step 2).toSeq
    if (peaksB.size == kMax) {
      minCost = Math.min(minCost, calculateCost(peaksB, nums))
    }

    // If for some reason K_max > 0 but neither configuration yields K_max (highly unlikely for dense packing),
    // we might need a general search, but based on typical contest analysis, the dense packing must be optimal.
    if (minCost == Long.MaxValue) {
        // Fallback or error state, but for safety, return 0 if no peaks possible (though kMax handles this).
        0L
    } else {
      minCost
    }
  }
}
