object Solution {
  /**
    * @param nums The input array.
    * @return The minimum total operations required.
    */
  def nums(nums: Array[Long]): Long = {
    val n = nums.length
    if (n < 3) {
      return 0L
    }

    // Maximum number of special indices possible is K_max = ceil((n - 2) / 2.0)
    // Using integer arithmetic: (n - 2 + 1) / 2 = (n - 1) / 2 in integer division if n-2 >= 0
    val kMax: Int = if (n >= 3) ((n - 2) + 1) / 2 else 0

    // Helper function to calculate the cost for a given set of peak indices
    def calculateCost(peakIndices: Seq[Int]): Long = {
      var currentCost: Long = 0
      for (i <- peakIndices) {
        var requiredValue: Long = 0

        // Check left neighbor (i-1)
        if (i > 0) {
          // Required value must be at least nums[i-1] + 1
          requiredValue = math.max(requiredValue, nums(i - 1) + 1)
        }
        // Check right neighbor (i+1)
        if (i < n - 1) {
          // Required value must be at least nums[i+1] + 1
          requiredValue = math.max(requiredValue, nums(i + 1) + 1)
        }

        // Calculate cost to reach requiredValue
        val costForThisPeak = math.max(0L, requiredValue - nums(i))
        currentCost += costForThisPeak
      }
      currentCost
    }

    var minCost: Long = Long.MaxValue

    // --- Candidate A: Odd indices (1, 3, 5, ...) ---
    var peaksA: Seq[Int] = Seq.empty
    var i = 1
    while (i <= n - 2) {
      peaksA = peaksA :+ i
      i += 2
    }

    if (peaksA.length == kMax) {
      minCost = math.min(minCost, calculateCost(peaksA))
    }

    // --- Candidate B: Even indices (2, 4, 6, ...) ---
    var peaksB: Seq[Int] = Seq.empty
    i = 2
    while (i <= n - 2) {
      peaksB = peaksB :+ i
      i += 2
    }

    if (peaksB.length == kMax) {
      minCost = math.min(minCost, calculateCost(peaksB))
    }

    // If K_max was 0 (i.e., n < 3), minCost is still MaxValue, but n < 3 is handled.
    // For n >= 3, kMax >= 1, and at least one of peaksA or peaksB (or both) must have length kMax.
    if (minCost == Long.MaxValue) {
        // This fallback should ideally not be hit for n >= 3 if the K_max logic is sound
        return 0L
    }

